if (!$env.GDA_DEPLOY_KEY_V2_CP) throw new Error('GDA_DEPLOY_KEY_V2_CP env var not set');
if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers['x-gda-auth'] || headers['x-gda-key'] || body.auth_key || body.deploy_key || '';
const origin = (headers.origin || headers.referer || headers['x-forwarded-host'] || '').toLowerCase();
const trustedOrigins = ['gda.csr-llc.tech', 'n8n.csr-llc.tech', 'localhost'];
const fromTrustedOrigin = trustedOrigins.some(function(o) { return origin.includes(o); });

function env(name, fallback) {
  try { if (typeof $env !== 'undefined' && $env[name]) return $env[name]; } catch (e) {}
  return fallback || '';
}
const webhookHeaderValue = env('GDA_WEBHOOK_HEADER_VALUE');
if (!webhookHeaderValue) throw new Error('GDA_WEBHOOK_HEADER_VALUE env var not set');

if (auth !== $env.GDA_WEBHOOK_SECRET_2026 && auth !== $env.GDA_DEPLOY_KEY_V2_CP && auth !== webhookHeaderValue && auth !== $env.GDA_API_KEY_2026 && !fromTrustedOrigin) {
  throw new Error('Unauthorized');
}
return $input.all();

const b = $('Webhook').first().json.body;
let agencyOpps = []; try { agencyOpps = $('Enrich: Same Agency Opps').all().map(i => i.json).filter(i => i.opp_title); } catch(e) {}
let pastPlans = []; try { pastPlans = $('Enrich: Past Capture Plans').all().map(i => i.json).filter(i => i.opportunity); } catch(e) {}
let lessons = []; try { lessons = $('Enrich: Capture Lessons').all().map(i => i.json).filter(i => i.lesson_text); } catch(e) {}

// EIS Win Themes
const EIS_WIN_THEMES = [
  '1. Incumbency with mission continuity: EIS holds PM Mission Command product support (APG MD / Ft Bliss / Ft Hood / Ft Gordon) — proven SECRET FCL, cleared workforce, zero disruption risk',
  '2. C5ISR / IEW&S domain depth: EIS technical staff have hands-on CP CE, MCE/JBC-P, FSC2/AFATDS, SMART, PdM CPI2 experience — not resume-matched generalists',
  '3. Army-centric culture: OU3 leadership speaks Army acquisition language, understands ACAT programs, PM structure, and PdM relationships',
  '4. Small business agility with enterprise reach: GDA OU3 can self-perform or team, price aggressively, and move fast without corporate bureaucracy',
  '5. Intelligence community IT crossover: EIS bridges Army tactical comms and IC IT — dual-market credibility for hybrid programs',
  '6. Shipley-disciplined capture: systematic phase-gate process, documented lessons learned, pwin-calibrated pipeline — evaluators see mature BD organization',
  '7. Past performance on classified programs: SECRET FCL active, cleared staff on ground at program sites — reduces re-badging risk for government'
];

// Incumbent intel by segment
const INCUMBENT_INTEL = {
  pm_mission_command: 'EIS IS the incumbent on TO# 47QFMA21K0015. Recompete strategy: emphasize zero defects on deliverables, staff retention, customer satisfaction scores.',
  army_c5isr: 'Typical incumbents: Booz Allen, SAIC, Leidos, General Dynamics IT, DXC Technology. EIS differentiator: on-site cleared presence, mission continuity, lower price point than large primes.',
  signals_intel: 'NSA/DIA contracts typically won by cleared SETA shops (CACI, Engility/SAIC, Booz). EIS entry strategy: team as sub to established prime, grow footprint.',
  ic_it: 'IC IT dominated by large ODCs (Leidos, SAIC, PAE). EIS play: niche task orders under existing vehicles (ITES-3S, CHESS, SEWP VI), not open market.',
  default: 'Research incumbent via USASpending.gov and GovTribe before capture kickoff. Key questions: incumbent performance record, prior award price (FOIA), set-aside history, small business goals.'
};

const agencyLower = (b.agency || '').toLowerCase();
const segKey = agencyLower.includes('mission command') ? 'pm_mission_command'
  : agencyLower.includes('signal') || agencyLower.includes('iew') ? 'signals_intel'
  : agencyLower.includes('nsa') || agencyLower.includes('dia') || agencyLower.includes('ic ') ? 'ic_it'
  : agencyLower.includes('army') || agencyLower.includes('c5isr') ? 'army_c5isr'
  : 'default';
const incumbentContext = INCUMBENT_INTEL[segKey];

const winThemesText = EIS_WIN_THEMES.join('\n');
const oppContextText = agencyOpps.length > 0
  ? agencyOpps.map(o => '- ' + o.opp_title + ' ($' + (o.estimated_value || 'TBD') + ', fit:' + (o.eis_fit_score || '?') + ')').join('\n')
  : 'None found';
const lessonsText = lessons.length > 0
  ? lessons.map(l => '- [' + (l.outcome || '?') + '] ' + l.lesson_text).join('\n')
  : 'None';
const pastPlansText = pastPlans.length > 0
  ? pastPlans.map(p => '- ' + p.opportunity + ' (' + p.agency + '): ' + (p.exec_summary || 'no summary')).join('\n')
  : 'None';

const prompt = 'You are a Shipley-certified capture strategist for Envision Innovative Solutions (EIS), the defense analytics operating unit OU3 within Georgetown Defense Analytics (GDA). EIS focuses on Army C5ISR, IEW&S, signals intelligence, and intelligence community IT. EIS holds an active SECRET Facility Clearance (FCL).\n\nGENERATE A CAPTURE PLAN FOR:\nOpportunity: ' + (b.opportunity || 'Unknown') + '\nAgency/Customer: ' + (b.agency || 'Unknown') + '\nEstimated Value: ' + (b.contract_value || 'TBD') + '\n\nEIS WIN THEMES (use these as the foundation for win strategy):\n' + winThemesText + '\n\nINCUMBENT INTELLIGENCE FOR THIS MARKET SEGMENT:\n' + incumbentContext + '\n\nRELATED AGENCY OPPORTUNITIES IN EIS PIPELINE:\n' + oppContextText + '\n\nPAST CAPTURE PLAN CONTEXT:\n' + pastPlansText + '\n\nLESSONS LEARNED FROM PRIOR CAPTURES:\n' + lessonsText + '\n\nINSTRUCTIONS:\n- Select 3-5 win themes most relevant to this specific opportunity\n- Assess competitive position honestly — identify likely incumbent and how EIS beats them on price, past performance, or technical approach\n- confidence_score = 0-100 based on EIS strategic fit, past performance relevance, and competitive landscape\n- All action items must be time-bound with a specific owner role (e.g., Capture Manager, BD Lead, Technical Lead, Contracts)\n- data_gaps should list specific unknowns that must be resolved before go/no-go\n\nRESPOND ONLY WITH VALID JSON — no markdown, no preamble:\n{"lead_company": "Envision Innovative Solutions (EIS)", "executive_summary": "", "confidence_score": 0, "win_themes": [], "competitive_assessment": {"likely_incumbent": "", "known_competitors": [], "eis_advantage": "", "price_position": ""}, "action_items": [{"action": "", "owner": "", "due": "", "priority": ""}], "risk_assessment": [{"risk": "", "likelihood": "", "impact": "", "mitigation": ""}], "data_gaps": []}';

return [{json: {prompt, opportunity: b.opportunity, agency: b.agency, contract_value: b.contract_value}}];

const raw = $input.first().json;
const ctx = $('Build Capture Prompt').first().json;
let text = '';
if (raw.content && Array.isArray(raw.content)) { text = raw.content.map(c => c.text || '').join(''); } else { text = JSON.stringify(raw); }
let plan = {};
try { const clean = text.replace(/```json/g,'').replace(/```/g,'').trim(); plan = JSON.parse(clean); } catch(e) { const m = text.match(/\{[\s\S]*\}/); if (m) try { plan = JSON.parse(m[0]); } catch(e2) { plan = {error: 'Parse failed'}; } }
return [{json: {status:'ok', opportunity:ctx.opportunity, agency:ctx.agency, contract_value:ctx.contract_value, plan:plan, generated_at:new Date().toISOString()}}];

const b = $('Webhook').first().json.body;
const opp = b.opportunity || '';
const ag = b.agency || '';
const cv = b.contract_value || '';
const pd = JSON.stringify(b.plan || {});
const ot = b.opp_title || b.opportunity || '';
const planId = b.plan_id ? parseInt(b.plan_id) : null;
return [{json: {opp, ag, cv, pd, ot, planId, isUpdate: !!planId}}];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const plan = $input.first().json;
const planId = plan.id || plan.rows?.[0]?.id;
const oppTitle = plan.opp_title || '';
const agency = plan.agency || '';
const naics = plan.naics_code || '';
const key = $env.GDA_WEBHOOK_SECRET_2026;

let compIntelResult = {};
let teamingResult = {};

try {
  const ci = await fetch('https://n8n.csr-llc.tech/webhook/gda-comp-intel-2', {
    method: 'POST',
    headers: { 'x-gda-key': key, 'Content-Type': 'application/json' },
    body: JSON.stringify({ opportunity: oppTitle, agency, naics, auto_trigger: true })
  });
  compIntelResult = await ci.json();
} catch(e) { compIntelResult = { error: e.message }; }

try {
  const tm = await fetch('https://n8n.csr-llc.tech/webhook/gda-teaming-scorer', {
    method: 'POST',
    headers: { 'x-gda-key': key, 'Content-Type': 'application/json' },
    body: JSON.stringify({ opportunity: oppTitle, agency, naics, auto_trigger: true })
  });
  teamingResult = await tm.json();
} catch(e) { teamingResult = { error: e.message }; }

return [{ json: { plan_id: planId, opp_title: oppTitle, agency, comp_intel: compIntelResult, teaming: teamingResult } }];
